`include "config.svh" // Here lives a bunch of macro flags...

import float_flag_pkg::*;
import sp_mode_pkg::*;
import float_metadata_pkg::*;
import binary128_pkg::*;
import binary64_pkg::*;
import binary32_pkg::*;
import binary128_convert_pkg::*;
import fixed128_pkg::*;
import fixed64_pkg::*;
import fixed32_pkg::*;

/**
 * Some parts of this module is written in a way that make this module highly reusable
 * whether you want to use 128 reusable LUT or not, and those parts are gated by parameters
 * which the synthesizer should be smart enough to exclude when compiling, as long as you
 * set the correct parameter flags. But to be safe this macro gates the compilation of those
 * parts if needed.
 * 
 * When this macro is set, those lines of code will be excluded by the compilation like a c
 * macro and will not be included in the synthesized hardware, hence "hardware" "blockout".
 */
// `define HARDWARE_BLOCKOUT

module fixed_partition_sp #(
  parameter int MODULE_LATENCY_128    = 2,
  parameter int MODULE_LATENCY_64     = 4,
  parameter int MODULE_LATENCY_32     = 5,
  
  // Behavior controls
  parameter bit HAS_SIGN              = 1'b0, // MSB is sign bit when set
  parameter bit USE_128_FOR_64        = 1'b0, // derive 64 outputs from 128 LUT
  parameter bit USE_128_FOR_32        = 1'b0, // derive 32 outputs from 128 LUT
  parameter bit ENABLE_64             = 1'b1,
  parameter bit ENABLE_32             = 1'b1,

  // Address widths (excluding sign bit)
  parameter int ADDR_BITS_128         = 13,
  parameter int ADDR_BITS_64          = 13,
  parameter int ADDR_BITS_32          = 10,
  parameter int LANE_BITS_128         = ADDR_BITS_128 + (HAS_SIGN ? 1 : 0),
  parameter int LANE_BITS_64          = ADDR_BITS_64  + (HAS_SIGN ? 1 : 0),
  parameter int LANE_BITS_32          = ADDR_BITS_32  + (HAS_SIGN ? 1 : 0),

  // LUT files (use *_POS/_NEG when HAS_SIGN=1, otherwise *_FILE)
  parameter string INIT_128_POS_FILE  = "",
  parameter string INIT_128_NEG_FILE  = "",
  parameter string INIT_128_FILE      = "",
  parameter string INIT_64_POS_FILE   = "",
  parameter string INIT_64_NEG_FILE   = "",
  parameter string INIT_64_FILE       = "",
  parameter string INIT_32_POS_FILE   = "",
  parameter string INIT_32_NEG_FILE   = "",
  parameter string INIT_32_FILE       = "",

  // Error and debug parameters
  parameter int ERROR_SIGNAL_NUM_BITS = 32,
  parameter int DEBUG_SIGNAL_NUM_BITS = 32,

  // Identifier const
  parameter logic [3:0] MODULE_IDENTIFIER = 4'b0000
) (
  input   logic                                   i_clk,
  input   logic                                   i_rst_n, // Synchronous

  // Metadata stuff
  input   var float_metadata_t                    i_metadata,
  output  var float_metadata_t                    o_metadata,

  // Data inputs by mode
  input   logic [LANE_BITS_128-1:0]               i_lane_128,
  input   logic [LANE_BITS_64-1:0]                i_lane_64a,
  input   logic [LANE_BITS_64-1:0]                i_lane_64b,
  input   logic [LANE_BITS_32-1:0]                i_lane_32a,
  input   logic [LANE_BITS_32-1:0]                i_lane_32b,
  input   logic [LANE_BITS_32-1:0]                i_lane_32c,
  input   logic [LANE_BITS_32-1:0]                i_lane_32d,

  // Data outputs
  output  binary128_t                             o_exp_a128,
  output  binary64_t                              o_exp_a64a,
  output  binary64_t                              o_exp_a64b,
  output  binary32_t                              o_exp_a32a,
  output  binary32_t                              o_exp_a32b,
  output  binary32_t                              o_exp_a32c,
  output  binary32_t                              o_exp_a32d,

  // Upstream Handshake
  input   logic                                   i_valid128,
  input   logic                                   i_valid64a,
  input   logic                                   i_valid64b,
  input   logic                                   i_valid32a,
  input   logic                                   i_valid32b,
  input   logic                                   i_valid32c,
  input   logic                                   i_valid32d,

  // Downstream Handshake
  output  logic                                   o_valid128,
  output  logic                                   o_valid64a,
  output  logic                                   o_valid64b,
  output  logic                                   o_valid32a,
  output  logic                                   o_valid32b,
  output  logic                                   o_valid32c,
  output  logic                                   o_valid32d,

  // Module identifier
  output  logic [3:0]                             o_sanity_identifier,

  // Error and debug signals
  output  logic [ERROR_SIGNAL_NUM_BITS-1:0]       o_error,
  output  logic [DEBUG_SIGNAL_NUM_BITS-1:0]       o_debug
);

localparam int DEPTH_128 = (ADDR_BITS_128 > 0) ? (1 << ADDR_BITS_128) : 1;
localparam int DEPTH_64  = (ADDR_BITS_64  > 0) ? (1 << ADDR_BITS_64)  : 1;
localparam int DEPTH_32  = (ADDR_BITS_32  > 0) ? (1 << ADDR_BITS_32)  : 1;

function automatic logic [ADDR_BITS_128-1:0] addr128_from_64(
  input logic [ADDR_BITS_64-1:0] addr64
);
  addr128_from_64 = addr64;
endfunction

function automatic logic [ADDR_BITS_128-1:0] addr128_from_32(
  input logic [ADDR_BITS_32-1:0] addr32
);
  addr128_from_32 = addr32;
endfunction

//=====================================================================================
// LUTs
//=====================================================================================
// Force BRAM inference even for smaller partitions (e.g., partition A), otherwise
// Vivado may choose to implement the ROM as distributed (LUT) ROM and consume LUTs.
(* ram_style = "block", rom_style = "block" *) logic [127:0] mem128_pos  [0:DEPTH_128-1];
(* ram_style = "block", rom_style = "block" *) logic [127:0] mem128_neg  [0:DEPTH_128-1];

initial begin
  if (HAS_SIGN) begin
    if (INIT_128_POS_FILE != "") `SPEX_READMEM(INIT_128_POS_FILE, mem128_pos);
    if (INIT_128_NEG_FILE != "") `SPEX_READMEM(INIT_128_NEG_FILE, mem128_neg);
  end
  else begin
    if (INIT_128_FILE != "") `SPEX_READMEM(INIT_128_FILE, mem128_pos);
  end
end


//=====================================================================================
// Module body
//=====================================================================================
// Default stuff out
logic [DEBUG_SIGNAL_NUM_BITS-1:0]   s_o_debug;
logic [ERROR_SIGNAL_NUM_BITS-1:0]   s_o_error;
always_ff @( posedge i_clk ) begin : defaulter
  if (!i_rst_n) begin
    s_o_error <= '0;
    s_o_debug <= '0;
  end
end

/**
 * Stage 1b registers: Propogate valid bits and metadata across stages.
 *
 * Note: in FOUR_SP_MODE, lanes c/d are read one stage later (time-muxed)
 * from the same BRAM, so we must buffer i_lane_32c/d here.
 */
logic                     s_S1b_valid128;
logic                     s_S1b_valid64a;
logic                     s_S1b_valid64b;
logic                     s_S1b_valid32a;
logic                     s_S1b_valid32b;
logic                     s_S1b_valid32c;
logic                     s_S1b_valid32d;
logic [LANE_BITS_32-1:0]  s_S1b_lane_32c;
logic [LANE_BITS_32-1:0]  s_S1b_lane_32d;
float_metadata_t          s_S1b_metadata;

/**
 *
 * State transition control
 *
 */
localparam int PIPE_DEPTH = (MODULE_LATENCY_32 < 4) ? 4 : MODULE_LATENCY_32;
logic [PIPE_DEPTH-1 : 0]  s_pipe_valid;
logic [PIPE_DEPTH-1 : 0]  s_pipe_valid_next;

localparam int S2_OFFSET = 0;
localparam int S3_OFFSET = S2_OFFSET + 1;
localparam int S4_OFFSET = S3_OFFSET + 1;
localparam int S5_OFFSET = S4_OFFSET + 1;

// Decode the input valid signals
logic s_fire_raw;
assign s_fire_raw = i_metadata.sp_mode == SINGLE_MODE  ? i_valid128 :
                    i_metadata.sp_mode == TWO_SP_MODE  ? (i_valid64a & i_valid64b) :
                    i_metadata.sp_mode == FOUR_SP_MODE ? (i_valid32a & i_valid32b & i_valid32c & i_valid32d) :
                    '0;

/**
 * In FOUR_SP_MODE, we need 4 reads (a/b/c/d). Since the LUT is a true dual-port
 * ROM, lanes c/d are read in stage 2 (one cycle later). During that cycle the
 * BRAM ports are fully occupied, so we must not accept a new input.
 */
logic s_stage2_four_read;
assign s_stage2_four_read = s_pipe_valid[S2_OFFSET] &&
                            ENABLE_32 && USE_128_FOR_32 &&
                            (s_S1b_metadata.sp_mode == FOUR_SP_MODE);

logic s_mem_busy;
assign s_mem_busy = s_stage2_four_read;

logic s_fire;
assign s_fire = s_fire_raw & ~s_mem_busy;

assign s_pipe_valid_next = {s_pipe_valid[PIPE_DEPTH-2 : 0], s_fire};

logic s_S1_en, s_S2_en, s_S3_en, s_S4_en, s_S5_en;
assign s_S1_en = s_fire;
assign s_S2_en = s_pipe_valid[S2_OFFSET];
assign s_S3_en = s_pipe_valid[S3_OFFSET];
assign s_S4_en = s_pipe_valid[S4_OFFSET];
assign s_S5_en = s_pipe_valid[S5_OFFSET];

/**
 * FSM
 */
always_ff @( posedge i_clk ) begin : sp_intmultiplier_FSM
  if (!i_rst_n) begin
    s_pipe_valid <= '0;
  end
  else begin
    s_pipe_valid <= s_pipe_valid_next;
  end
end

//=====================================================================================
// Stage 1/2: Read LUTs (single true dual-port BRAM inference)
//=====================================================================================
logic [63:0]  s_S1a_exp_a64a_64_bits;
logic [63:0]  s_S1a_exp_a64b_64_bits;
logic [31:0]  s_S1a_exp_a32a_32_bits;
logic [31:0]  s_S1a_exp_a32b_32_bits;
logic [31:0]  s_S2a_exp_a32c_32_bits;
logic [31:0]  s_S2a_exp_a32d_32_bits;

logic [ADDR_BITS_128-1:0] s_mem_addra;
logic [ADDR_BITS_128-1:0] s_mem_addrb;
logic                     s_mem_ena;
logic                     s_mem_enb;
logic                     s_mem_use_neg_a;
logic                     s_mem_use_neg_b;
logic [127:0]             s_mem_douta;
logic [127:0]             s_mem_doutb;

always_comb begin : mem128_port_select
  s_mem_ena       = 1'b0;
  s_mem_enb       = 1'b0;
  s_mem_addra     = '0;
  s_mem_addrb     = '0;
  s_mem_use_neg_a = 1'b0;
  s_mem_use_neg_b = 1'b0;

  if (s_stage2_four_read) begin
    // Stage 2 FOUR_SP_MODE read: lanes c/d
    s_mem_ena   = 1'b1;
    s_mem_enb   = 1'b1;
    s_mem_addra = addr128_from_32(s_S1b_lane_32c[ADDR_BITS_32-1:0]);
    s_mem_addrb = addr128_from_32(s_S1b_lane_32d[ADDR_BITS_32-1:0]);
    if (HAS_SIGN) begin
      s_mem_use_neg_a = s_S1b_lane_32c[LANE_BITS_32-1];
      s_mem_use_neg_b = s_S1b_lane_32d[LANE_BITS_32-1];
    end
  end
  else if (s_S1_en) begin
    // Stage 1 read: SINGLE/TWO/FOUR (lanes a/b)
    case (i_metadata.sp_mode)
      SINGLE_MODE: begin
        s_mem_ena   = 1'b1;
        s_mem_addra = i_lane_128[ADDR_BITS_128-1:0];
        if (HAS_SIGN) begin
          s_mem_use_neg_a = i_lane_128[LANE_BITS_128-1];
        end
      end

      TWO_SP_MODE: begin
        if (ENABLE_64 && USE_128_FOR_64) begin
          s_mem_ena   = 1'b1;
          s_mem_enb   = 1'b1;
          s_mem_addra = addr128_from_64(i_lane_64a[ADDR_BITS_64-1:0]);
          s_mem_addrb = addr128_from_64(i_lane_64b[ADDR_BITS_64-1:0]);
          if (HAS_SIGN) begin
            s_mem_use_neg_a = i_lane_64a[LANE_BITS_64-1];
            s_mem_use_neg_b = i_lane_64b[LANE_BITS_64-1];
          end
        end
      end

      FOUR_SP_MODE: begin
        if (ENABLE_32 && USE_128_FOR_32) begin
          s_mem_ena   = 1'b1;
          s_mem_enb   = 1'b1;
          s_mem_addra = addr128_from_32(i_lane_32a[ADDR_BITS_32-1:0]);
          s_mem_addrb = addr128_from_32(i_lane_32b[ADDR_BITS_32-1:0]);
          if (HAS_SIGN) begin
            s_mem_use_neg_a = i_lane_32a[LANE_BITS_32-1];
            s_mem_use_neg_b = i_lane_32b[LANE_BITS_32-1];
          end
        end
      end

      default: begin
        // No-op
      end
    endcase
  end
end

always_ff @( posedge i_clk ) begin : mem128_tdp_rom
  if (!i_rst_n) begin
    s_mem_douta <= '0;
    s_mem_doutb <= '0;
  end
  else begin
    if (s_mem_ena) begin
      s_mem_douta <= (HAS_SIGN && s_mem_use_neg_a) ? mem128_neg[s_mem_addra] : mem128_pos[s_mem_addra];
    end
    if (s_mem_enb) begin
      s_mem_doutb <= (HAS_SIGN && s_mem_use_neg_b) ? mem128_neg[s_mem_addrb] : mem128_pos[s_mem_addrb];
    end
  end
end

/**
 * Stage 1b block: Propogate valid bit and metadata bits
 */
always_ff @( posedge i_clk ) begin : stage1b
  if (!i_rst_n) begin
    s_S1b_valid128 <= '0;
    s_S1b_valid64a <= '0;
    s_S1b_valid64b <= '0;
    s_S1b_valid32a <= '0;
    s_S1b_valid32b <= '0;
    s_S1b_valid32c <= '0;
    s_S1b_valid32d <= '0;
    s_S1b_lane_32c <= '0;
    s_S1b_lane_32d <= '0;
    s_S1b_metadata <= '0;
  end
  else begin
    s_S1b_valid128 <= s_S1_en & i_valid128;
    s_S1b_valid64a <= s_S1_en & i_valid64a;
    s_S1b_valid64b <= s_S1_en & i_valid64b;
    s_S1b_valid32a <= s_S1_en & i_valid32a;
    s_S1b_valid32b <= s_S1_en & i_valid32b;
    s_S1b_valid32c <= s_S1_en & i_valid32c;
    s_S1b_valid32d <= s_S1_en & i_valid32d;
    if (s_S1_en) begin
      s_S1b_lane_32c <= i_lane_32c;
      s_S1b_lane_32d <= i_lane_32d;
    end
    s_S1b_metadata <= i_metadata;
  end
end


//=====================================================================================
// Stage 2: Convert lane a and b of 64b and 32b (part 1), read lane c and d of 32b;
//          128b "early exit" here
//=====================================================================================
/**
 * Stage 2b: Convert lane a/b (part 1) for 64b and 32b.
 *           128b "early exit" is still here.
 */
binary128_t  s_S2b_exp_a128;
binary64_t   s_S2b_exp_a64a;
binary64_t   s_S2b_exp_a64b;
binary32_t   s_S2b_exp_a32a;
binary32_t   s_S2b_exp_a32b;
binary128_to_binary64_rne_p1_t s_S2b_exp_a64a_p1;
binary128_to_binary64_rne_p1_t s_S2b_exp_a64b_p1;
binary128_to_binary32_rne_p1_t s_S2b_exp_a32a_p1;
binary128_to_binary32_rne_p1_t s_S2b_exp_a32b_p1;
always_ff @( posedge i_clk ) begin : stage2b
  if (!i_rst_n) begin
    s_S2b_exp_a128    <= '0;
    s_S2b_exp_a64a    <= '0;
    s_S2b_exp_a64b    <= '0;
    s_S2b_exp_a32a    <= '0;
    s_S2b_exp_a32b    <= '0;
    s_S2b_exp_a64a_p1 <= '0;
    s_S2b_exp_a64b_p1 <= '0;
    s_S2b_exp_a32a_p1 <= '0;
    s_S2b_exp_a32b_p1 <= '0;
  end
  else begin
	    if (s_S2_en) begin
	      case (s_S1b_metadata.sp_mode)
	        SINGLE_MODE: begin
	          s_S2b_exp_a128 <= binary128_t'(s_mem_douta);
	        end
	
	        TWO_SP_MODE: begin
	          if (ENABLE_64) begin
	            if (USE_128_FOR_64) begin
	              s_S2b_exp_a64a_p1 <= binary128_to_binary64_rne_part1(binary128_t'(s_mem_douta));
	              s_S2b_exp_a64b_p1 <= binary128_to_binary64_rne_part1(binary128_t'(s_mem_doutb));
	              s_S2b_exp_a64a <= '0;
	              s_S2b_exp_a64b <= '0;
	            end
	            else begin
              s_S2b_exp_a64a <= binary64_t'(s_S1a_exp_a64a_64_bits);
              s_S2b_exp_a64b <= binary64_t'(s_S1a_exp_a64b_64_bits);
              s_S2b_exp_a64a_p1 <= '0;
              s_S2b_exp_a64b_p1 <= '0;
              end
            end
          else begin
            s_S2b_exp_a64a <= '0;
            s_S2b_exp_a64b <= '0;
            s_S2b_exp_a64a_p1 <= '0;
            s_S2b_exp_a64b_p1 <= '0;
          end
        end

	        FOUR_SP_MODE: begin
	          if (ENABLE_32) begin
	            if (USE_128_FOR_32) begin
	              s_S2b_exp_a32a_p1 <= binary128_to_binary32_rne_part1(binary128_t'(s_mem_douta));
	              s_S2b_exp_a32b_p1 <= binary128_to_binary32_rne_part1(binary128_t'(s_mem_doutb));
	              s_S2b_exp_a32a <= '0;
	              s_S2b_exp_a32b <= '0;
	            end
	            else begin
              s_S2b_exp_a32a <= binary32_t'(s_S1a_exp_a32a_32_bits);
              s_S2b_exp_a32b <= binary32_t'(s_S1a_exp_a32b_32_bits);
              s_S2b_exp_a32a_p1 <= '0;
              s_S2b_exp_a32b_p1 <= '0;
            end
          end
          else begin
            s_S2b_exp_a32a <= '0;
            s_S2b_exp_a32b <= '0;
            s_S2b_exp_a32a_p1 <= '0;
            s_S2b_exp_a32b_p1 <= '0;
          end
        end

        default: begin
          assert (0) else begin
            // s_o_error[1] <= 1'b1;
          end
        end
      endcase
    end
  end
end

/**
 * Stage 2c: Signals (valid and metadata bits) passthrough
 */
logic             s_S2c_valid128;
logic             s_S2c_valid64a;
logic             s_S2c_valid64b;
logic             s_S2c_valid32a;
logic             s_S2c_valid32b;
logic             s_S2c_valid32c;
logic             s_S2c_valid32d;
float_metadata_t  s_S2c_metadata;
always_ff @( posedge i_clk ) begin : stage2c_signal_passthrough
  if (!i_rst_n) begin
    s_S2c_valid128 <= '0;
    s_S2c_valid64a <= '0;
    s_S2c_valid64b <= '0;
    s_S2c_valid32a <= '0;
    s_S2c_valid32b <= '0;
    s_S2c_valid32c <= '0;
    s_S2c_valid32d <= '0;
    s_S2c_metadata <= '0;
  end
  else begin
    if (s_S2_en) begin
      s_S2c_valid128 <= s_S1b_valid128;
      s_S2c_valid64a <= s_S1b_valid64a;
      s_S2c_valid64b <= s_S1b_valid64b;
      s_S2c_valid32a <= s_S1b_valid32a;
      s_S2c_valid32b <= s_S1b_valid32b;
      s_S2c_valid32c <= s_S1b_valid32c;
      s_S2c_valid32d <= s_S1b_valid32d;
      s_S2c_metadata <= s_S1b_metadata;
    end // if (s_S2_en)
    else begin
      s_S2c_valid128 <= '0;
      s_S2c_valid64a <= '0;
      s_S2c_valid64b <= '0;
      s_S2c_valid32a <= '0;
      s_S2c_valid32b <= '0;
      s_S2c_valid32c <= '0;
      s_S2c_valid32d <= '0;
      s_S2c_metadata <= '0;
    end
  end // else begin
end // stage2c_signal_passthrough


//=====================================================================================
// Stage 3:
// - 64: part2(a,b)
// - 32: part2(a,b), part1(c,d)
//=====================================================================================
logic                         s_S3_valid64a;
logic                         s_S3_valid64b;
logic                         s_S3_valid32a;
logic                         s_S3_valid32b;
logic                         s_S3_valid32c;
logic                         s_S3_valid32d;
logic                         s_S3_valid32_quad;
float_metadata_t              s_S3_metadata;
binary64_t                    s_S3_exp_a64a;
binary64_t                    s_S3_exp_a64b;
binary32_t                    s_S3_exp_a32a;
binary32_t                    s_S3_exp_a32b;
binary32_t                    s_S3_exp_a32c;
binary32_t                    s_S3_exp_a32d;
binary128_to_binary64_rne_p2_t s_S3_exp_a64a_p2;
binary128_to_binary64_rne_p2_t s_S3_exp_a64b_p2;
binary128_to_binary32_rne_p2_t s_S3_exp_a32a_p2;
binary128_to_binary32_rne_p2_t s_S3_exp_a32b_p2;
binary128_to_binary32_rne_p1_t s_S3_exp_a32c_p1;
binary128_to_binary32_rne_p1_t s_S3_exp_a32d_p1;
always_ff @( posedge i_clk ) begin : stage3_conversion_part2_and_cd_part1
  if (!i_rst_n) begin
    s_S3_valid64a      <= '0;
    s_S3_valid64b      <= '0;
    s_S3_valid32a      <= '0;
    s_S3_valid32b      <= '0;
    s_S3_valid32c      <= '0;
    s_S3_valid32d      <= '0;
    s_S3_valid32_quad  <= '0;
    s_S3_metadata      <= '0;

    s_S3_exp_a64a      <= '0;
    s_S3_exp_a64b      <= '0;
    s_S3_exp_a32a      <= '0;
    s_S3_exp_a32b      <= '0;
    s_S3_exp_a32c      <= '0;
    s_S3_exp_a32d      <= '0;
    s_S3_exp_a64a_p2   <= '0;
    s_S3_exp_a64b_p2   <= '0;
    s_S3_exp_a32a_p2   <= '0;
    s_S3_exp_a32b_p2   <= '0;
    s_S3_exp_a32c_p1   <= '0;
    s_S3_exp_a32d_p1   <= '0;
  end
  else begin
    if (s_S3_en) begin
      s_S3_valid64a  <= s_S2c_valid64a;
      s_S3_valid64b  <= s_S2c_valid64b;
      s_S3_metadata  <= s_S2c_metadata;

      if (ENABLE_64 && USE_128_FOR_64 && s_S2c_metadata.sp_mode == TWO_SP_MODE) begin
        s_S3_exp_a64a_p2    <= binary128_to_binary64_rne_part2(s_S2b_exp_a64a_p1);
        s_S3_exp_a64b_p2    <= binary128_to_binary64_rne_part2(s_S2b_exp_a64b_p1);
        s_S3_exp_a64a       <= '0;
        s_S3_exp_a64b       <= '0;
      end
      else begin
        s_S3_exp_a64a       <= s_S2b_exp_a64a;
        s_S3_exp_a64b       <= s_S2b_exp_a64b;
        s_S3_exp_a64a_p2    <= '0;
        s_S3_exp_a64b_p2    <= '0;
      end

      if (ENABLE_32 && USE_128_FOR_32 && s_S2c_metadata.sp_mode == FOUR_SP_MODE) begin
        s_S3_exp_a32a_p2    <= binary128_to_binary32_rne_part2(s_S2b_exp_a32a_p1);
        s_S3_exp_a32b_p2    <= binary128_to_binary32_rne_part2(s_S2b_exp_a32b_p1);
        s_S3_exp_a32c_p1    <= binary128_to_binary32_rne_part1(binary128_t'(s_mem_douta));
        s_S3_exp_a32d_p1    <= binary128_to_binary32_rne_part1(binary128_t'(s_mem_doutb));
        s_S3_exp_a32a       <= '0;
        s_S3_exp_a32b       <= '0;
        s_S3_exp_a32c       <= '0;
        s_S3_exp_a32d       <= '0;
        s_S3_valid32a       <= '0;
        s_S3_valid32b       <= '0;
        s_S3_valid32c       <= '0;
        s_S3_valid32d       <= '0;
        s_S3_valid32_quad   <= s_S2c_valid32a & s_S2c_valid32b & s_S2c_valid32c & s_S2c_valid32d;
      end
      else begin
        s_S3_exp_a32a       <= s_S2b_exp_a32a;
        s_S3_exp_a32b       <= s_S2b_exp_a32b;
        s_S3_exp_a32c       <= '0;
        s_S3_exp_a32d       <= '0;
        s_S3_exp_a32a_p2    <= '0;
        s_S3_exp_a32b_p2    <= '0;
        s_S3_exp_a32c_p1    <= '0;
        s_S3_exp_a32d_p1    <= '0;
        s_S3_valid32a       <= s_S2c_valid32a;
        s_S3_valid32b       <= s_S2c_valid32b;
        s_S3_valid32c       <= s_S2c_valid32c;
        s_S3_valid32d       <= s_S2c_valid32d;
        s_S3_valid32_quad   <= '0;
      end
    end // if (s_S3_en)
    else begin
      s_S3_valid64a      <= '0;
      s_S3_valid64b      <= '0;
      s_S3_valid32a      <= '0;
      s_S3_valid32b      <= '0;
      s_S3_valid32c      <= '0;
      s_S3_valid32d      <= '0;
      s_S3_valid32_quad  <= '0;
      s_S3_metadata      <= '0;

      s_S3_exp_a64a      <= '0;
      s_S3_exp_a64b      <= '0;
      s_S3_exp_a32a      <= '0;
      s_S3_exp_a32b      <= '0;
      s_S3_exp_a32c      <= '0;
      s_S3_exp_a32d      <= '0;
      s_S3_exp_a64a_p2   <= '0;
      s_S3_exp_a64b_p2   <= '0;
      s_S3_exp_a32a_p2   <= '0;
      s_S3_exp_a32b_p2   <= '0;
      s_S3_exp_a32c_p1   <= '0;
      s_S3_exp_a32d_p1   <= '0;
    end // else begin
  end // else begin
end // stage3_conversion_part2_and_cd_part1


//=====================================================================================
// Stage 4:
// - 64: part3(a,b)
// - 32: part3(a,b), part2(c,d)
//=====================================================================================
logic                          s_S4_valid64a;
logic                          s_S4_valid64b;
logic                          s_S4_valid32a;
logic                          s_S4_valid32b;
logic                          s_S4_valid32c;
logic                          s_S4_valid32d;
logic                          s_S4_valid32_quad;
float_metadata_t               s_S4_metadata;
binary64_t                     s_S4_exp_a64a;
binary64_t                     s_S4_exp_a64b;
binary32_t                     s_S4_exp_a32a;
binary32_t                     s_S4_exp_a32b;
binary32_t                     s_S4_exp_a32c;
binary32_t                     s_S4_exp_a32d;
binary128_to_binary32_rne_p2_t s_S4_exp_a32c_p2;
binary128_to_binary32_rne_p2_t s_S4_exp_a32d_p2;

always_ff @( posedge i_clk ) begin : stage4_conversion_part3_and_cd_part2
  if (!i_rst_n) begin
    s_S4_valid64a <= '0;
    s_S4_valid64b <= '0;
    s_S4_valid32a <= '0;
    s_S4_valid32b <= '0;
    s_S4_valid32c <= '0;
    s_S4_valid32d <= '0;
    s_S4_valid32_quad <= '0;
    s_S4_metadata <= '0;
    s_S4_exp_a64a <= '0;
    s_S4_exp_a64b <= '0;
    s_S4_exp_a32a <= '0;
    s_S4_exp_a32b <= '0;
    s_S4_exp_a32c <= '0;
    s_S4_exp_a32d <= '0;
    s_S4_exp_a32c_p2 <= '0;
    s_S4_exp_a32d_p2 <= '0;
  end
  else begin
    if (s_S4_en) begin
      s_S4_metadata <= s_S3_metadata;
      s_S4_valid64a <= s_S3_valid64a;
      s_S4_valid64b <= s_S3_valid64b;

      if (ENABLE_64 && USE_128_FOR_64 && s_S3_metadata.sp_mode == TWO_SP_MODE) begin
        s_S4_exp_a64a <= binary128_to_binary64_rne_part3(s_S3_exp_a64a_p2);
        s_S4_exp_a64b <= binary128_to_binary64_rne_part3(s_S3_exp_a64b_p2);
      end
      else begin
        s_S4_exp_a64a <= s_S3_exp_a64a;
        s_S4_exp_a64b <= s_S3_exp_a64b;
      end

      if (ENABLE_32 && USE_128_FOR_32 && s_S3_metadata.sp_mode == FOUR_SP_MODE) begin
        s_S4_exp_a32a <= binary128_to_binary32_rne_part3(s_S3_exp_a32a_p2);
        s_S4_exp_a32b <= binary128_to_binary32_rne_part3(s_S3_exp_a32b_p2);
        s_S4_exp_a32c <= '0;
        s_S4_exp_a32d <= '0;
        s_S4_exp_a32c_p2 <= binary128_to_binary32_rne_part2(s_S3_exp_a32c_p1);
        s_S4_exp_a32d_p2 <= binary128_to_binary32_rne_part2(s_S3_exp_a32d_p1);
        s_S4_valid32a <= '0;
        s_S4_valid32b <= '0;
        s_S4_valid32c <= '0;
        s_S4_valid32d <= '0;
        s_S4_valid32_quad <= s_S3_valid32_quad;
      end
      else begin
        s_S4_exp_a32a <= s_S3_exp_a32a;
        s_S4_exp_a32b <= s_S3_exp_a32b;
        s_S4_exp_a32c <= s_S3_exp_a32c;
        s_S4_exp_a32d <= s_S3_exp_a32d;
        s_S4_exp_a32c_p2 <= '0;
        s_S4_exp_a32d_p2 <= '0;
        s_S4_valid32a <= s_S3_valid32a;
        s_S4_valid32b <= s_S3_valid32b;
        s_S4_valid32c <= s_S3_valid32c;
        s_S4_valid32d <= s_S3_valid32d;
        s_S4_valid32_quad <= '0;
      end
    end
    else begin
      s_S4_valid64a <= '0;
      s_S4_valid64b <= '0;
      s_S4_valid32a <= '0;
      s_S4_valid32b <= '0;
      s_S4_valid32c <= '0;
      s_S4_valid32d <= '0;
      s_S4_valid32_quad <= '0;
      s_S4_metadata <= '0;
      s_S4_exp_a64a <= '0;
      s_S4_exp_a64b <= '0;
      s_S4_exp_a32a <= '0;
      s_S4_exp_a32b <= '0;
      s_S4_exp_a32c <= '0;
      s_S4_exp_a32d <= '0;
      s_S4_exp_a32c_p2 <= '0;
      s_S4_exp_a32d_p2 <= '0;
    end
  end
end


//=====================================================================================
// Stage 5:
// - 32: part3(c,d) and align all four lane outputs
//=====================================================================================
logic             s_S5_valid32a;
logic             s_S5_valid32b;
logic             s_S5_valid32c;
logic             s_S5_valid32d;
float_metadata_t  s_S5_metadata;
binary32_t        s_S5_exp_a32a;
binary32_t        s_S5_exp_a32b;
binary32_t        s_S5_exp_a32c;
binary32_t        s_S5_exp_a32d;

always_ff @( posedge i_clk ) begin : stage5_lane_cd_part3_and_ab_alignment
  if (!i_rst_n) begin
    s_S5_valid32a <= '0;
    s_S5_valid32b <= '0;
    s_S5_valid32c <= '0;
    s_S5_valid32d <= '0;
    s_S5_metadata <= '0;
    s_S5_exp_a32a <= '0;
    s_S5_exp_a32b <= '0;
    s_S5_exp_a32c <= '0;
    s_S5_exp_a32d <= '0;
  end
  else begin
    if (s_S5_en) begin
      s_S5_metadata <= s_S4_metadata;
      if (ENABLE_32 && USE_128_FOR_32 && s_S4_metadata.sp_mode == FOUR_SP_MODE) begin
        s_S5_exp_a32a <= s_S4_exp_a32a;
        s_S5_exp_a32b <= s_S4_exp_a32b;
        s_S5_exp_a32c <= binary128_to_binary32_rne_part3(s_S4_exp_a32c_p2);
        s_S5_exp_a32d <= binary128_to_binary32_rne_part3(s_S4_exp_a32d_p2);
        s_S5_valid32a <= s_S4_valid32_quad;
        s_S5_valid32b <= s_S4_valid32_quad;
        s_S5_valid32c <= s_S4_valid32_quad;
        s_S5_valid32d <= s_S4_valid32_quad;
      end
      else begin
        s_S5_exp_a32a <= s_S4_exp_a32a;
        s_S5_exp_a32b <= s_S4_exp_a32b;
        s_S5_exp_a32c <= s_S4_exp_a32c;
        s_S5_exp_a32d <= s_S4_exp_a32d;
        s_S5_valid32a <= s_S4_valid32a;
        s_S5_valid32b <= s_S4_valid32b;
        s_S5_valid32c <= s_S4_valid32c;
        s_S5_valid32d <= s_S4_valid32d;
      end
    end
    else begin
      s_S5_valid32a <= '0;
      s_S5_valid32b <= '0;
      s_S5_valid32c <= '0;
      s_S5_valid32d <= '0;
      s_S5_metadata <= '0;
      s_S5_exp_a32a <= '0;
      s_S5_exp_a32b <= '0;
      s_S5_exp_a32c <= '0;
      s_S5_exp_a32d <= '0;
    end
  end
end


//=====================================================================================
// Final assignment
//=====================================================================================
assign o_metadata = (s_S2c_metadata.sp_mode === SINGLE_MODE) ? s_S2c_metadata : 
                    (s_S4_metadata.sp_mode === TWO_SP_MODE) ? s_S4_metadata :
                    s_S5_metadata;
assign o_exp_a128 = s_S2b_exp_a128;
assign o_exp_a64a = ENABLE_64 ? s_S4_exp_a64a : '0;
assign o_exp_a64b = ENABLE_64 ? s_S4_exp_a64b : '0;
assign o_exp_a32a = ENABLE_32 ? s_S5_exp_a32a : '0;
assign o_exp_a32b = ENABLE_32 ? s_S5_exp_a32b : '0;
assign o_exp_a32c = ENABLE_32 ? s_S5_exp_a32c : '0;
assign o_exp_a32d = ENABLE_32 ? s_S5_exp_a32d : '0;

assign o_valid128 = s_S2c_valid128;
assign o_valid64a = ENABLE_64 ? s_S4_valid64a : 1'b0;
assign o_valid64b = ENABLE_64 ? s_S4_valid64b : 1'b0;
assign o_valid32a = ENABLE_32 ? s_S5_valid32a : 1'b0;
assign o_valid32b = ENABLE_32 ? s_S5_valid32b : 1'b0;
assign o_valid32c = ENABLE_32 ? s_S5_valid32c : 1'b0;
assign o_valid32d = ENABLE_32 ? s_S5_valid32d : 1'b0;

assign o_sanity_identifier = MODULE_IDENTIFIER;
assign o_error = s_o_error;
assign o_debug = s_o_debug;

endmodule
